import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.B4Sg2J31.js";const d=JSON.parse('{"title":"Philosophy","description":"","frontmatter":{},"headers":[],"relativePath":"about-router.md","filePath":"about-router.md"}'),n={name:"about-router.md"};function i(l,e,c,s,h,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="philosophy" tabindex="-1">Philosophy <a class="header-anchor" href="#philosophy" aria-label="Permalink to &quot;Philosophy&quot;">​</a></h1><p><strong>You can always fix a bug in a library, but a bad architecture will turn your entire project into Hell.</strong></p><p>With that in mind, I have been on a never ending quest to find a simple but effective architecture to easily build mobx / react apps in particular. The journey so far has lead me to the following three points for a happy developer experience.</p><h2 id="app-architecture-design-fundamentals" tabindex="-1">App architecture design fundamentals <a class="header-anchor" href="#app-architecture-design-fundamentals" aria-label="Permalink to &quot;App architecture design fundamentals&quot;">​</a></h2><p>Note: these principles can be applied to any kind of software, <code>Bard router</code> was made to allow such implementations in a react / mobx context.</p><h3 id="clean-architecture-by-robert-c-martin-uncle-bob" tabindex="-1">Clean architecture by Robert C. Martin (Uncle Bob) <a class="header-anchor" href="#clean-architecture-by-robert-c-martin-uncle-bob" aria-label="Permalink to &quot;Clean architecture by Robert C. Martin (Uncle Bob)&quot;">​</a></h3><blockquote><p>“By separating the software into layers, and conforming to The Dependency Rule, you will create a system that is intrinsically testable, with all the benefits that implies.”</p></blockquote><p><a href="https://blog.cleancoder.com/uncle-bob/2012/08/13/the-clean-architecture.html" target="_blank" rel="noreferrer">Link to Robert site</a></p><h3 id="decouple-state-and-ui-by-mobx-author" tabindex="-1">Decouple state and UI by mobx author <a class="header-anchor" href="#decouple-state-and-ui-by-mobx-author" aria-label="Permalink to &quot;Decouple state and UI by mobx author&quot;">​</a></h3><blockquote><p>&quot;Strategies for dealing with routing, data fetching, authentication and workflow testing without the UI layer.&quot;</p></blockquote><p><a href="https://hackernoon.com/how-to-decouple-state-and-ui-a-k-a-you-dont-need-componentwillmount-cc90b787aa37" target="_blank" rel="noreferrer">Link to Michel Weststrate article</a></p><h3 id="app-shell-architecture" tabindex="-1">App shell architecture <a class="header-anchor" href="#app-shell-architecture" aria-label="Permalink to &quot;App shell architecture&quot;">​</a></h3><blockquote><p>&quot;An application shell (or app shell) architecture is one way to build a Progressive Web App that reliably and instantly loads on your users&#39; screens, similar to what you see in native applications.&quot;</p></blockquote><p><a href="https://developers.google.com/web/fundamentals/architecture/app-shell" target="_blank" rel="noreferrer">Link to developer.google.com</a></p>',14)])])}const b=t(n,[["render",i]]);export{d as __pageData,b as default};
